function binImg = fImg2x2Bin(img)%% image 2x2 binning (even number arrays only)%% binImg: binned image%% img: input image%% Written by Kei Nakamura% % 2014/4/7 ver.1: Created %% main bodymodI = mod(size(img),2);if modI(1)==1    img = img(2:end,:);endif modI(2) == 1    img = img(:,2:end);endbinImg = img(1:2:end,1:2:end);binImg(:,:) = binImg + img(2:2:end,1:2:end);binImg(:,:) = binImg + img(1:2:end,2:2:end);binImg(:,:) = binImg + img(2:2:end,2:2:end);
